  1	import _ from 'lodash';
  2	import * as React from 'react';
  3	import { Link, useLocation, useNavigate, matchPath } from 'react-router-dom-v5-compat';
  4	import { Nav, NavList, NavItem } from '@patternfly/react-core';
  5	import { navMenuItems } from '../../routes';
  6	import { kialiStyle } from 'styles/StyleUtils';
  7	import { ExternalServiceInfo } from '../../types/StatusState';
  8	import { KialiIcon } from 'config/KialiIcon';
  9	import { GetTracingUrlProvider } from '../../utils/tracing/UrlProviders';
 10	import { t } from 'utils/I18nUtils';
 11	import { isControlPlaneAccessible } from '../../utils/MeshUtils';
 12	import { isTempoService } from '../../utils/tracing/UrlProviders/Tempo';
 13	import { TempoUrlFormat } from '../../types/StatusState';
 14	
 15	const externalLinkStyle = kialiStyle({
 16	  $nest: {
 17	    '&:focus': {
 18	      backgroundColor: 'transparent',
 19	      $nest: {
 20	        '&::before': {
 21	          borderBottomWidth: '1px'
 22	        }
 23	      }
 24	    }
 25	  }
 26	});
 27	
 28	const navListStyle = kialiStyle({
 29	  padding: 0
 30	});
 31	
 32	const iconStyle = kialiStyle({
 33	  marginLeft: '0.5rem'
 34	});
 35	
 36	const ExternalLink = ({ href, name }: { href: string; name: string }): React.ReactElement => (
 37	  <NavItem isActive={false} key={name}>
 38	    <a className={externalLinkStyle} href={href} target="_blank" rel="noopener noreferrer">
 39	      {name} <KialiIcon.ExternalLink className={iconStyle} />
 40	    </a>
 41	  </NavItem>
 42	);
 43	
 44	type MenuProps = {
 45	  externalServices: ExternalServiceInfo[];
 46	  isNavOpen: boolean;
 47	};
 48	
 49	export const Menu: React.FC<MenuProps> = (props: MenuProps) => {
 50	  const navigate = useNavigate();
 51	  const { pathname } = useLocation();
 52	
 53	  const { isNavOpen } = props;
 54	
 55	  React.useEffect(() => {
 56	    // Dispatch an extra "resize" event when side menu toggle to force that metrics charts resize
 57	    setTimeout(() => {
 58	      window.dispatchEvent(new Event('resize'));
 59	    }, 200);
 60	  }, [isNavOpen]);
 61	
 62	  const renderMenuItems = (): React.ReactNode => {
 63	    const allNavMenuItems = navMenuItems;
 64	
 65	    const activeMenuItem = allNavMenuItems.find(item => {
 66	      let isRoute = matchPath({ path: item.to }, pathname) ? true : false;
 67	
 68	      if (!isRoute && item.pathsActive) {
 69	        isRoute = _.filter(item.pathsActive, path => path.test(pathname)).length > 0;
 70	      }
 71	
 72	      return isRoute;
 73	    });
 74	
 75	    const tracingUrlProvider = GetTracingUrlProvider(props.externalServices);
 76	    const baseTracingUrl = tracingUrlProvider?.HomeUrl();
 77	
 78	    // Helper function to build tracing URL with appropriate parameters
 79	    const buildTracingUrlWithParams = (baseUrl: string): string => {
 80	      const urlParams = new URLSearchParams();
 81	
 82	      // Find the tracing service to check its configuration
 83	      const tracingService = props.externalServices.find(service =>
 84	        ['tempo', 'jaeger'].includes(service.name.toLowerCase())
 85	      );
 86	
 87	      // Check if it's a Tempo service with OpenShift format
 88	      if (
 89	        tracingService &&
 90	        isTempoService(tracingService) &&
 91	        tracingService.tempoConfig?.urlFormat === TempoUrlFormat.OPENSHIFT
 92	      ) {
 93	        // Add OpenShift-specific parameters
 94	        if (tracingService.tempoConfig?.namespace) {
 95	          urlParams.append('namespace', tracingService.tempoConfig?.namespace);
 96	        }
 97	        if (tracingService.tempoConfig?.name) {
 98	          urlParams.append('name', tracingService.tempoConfig?.name);
 99	        }
100	        if (tracingService.tempoConfig?.tenant) {
101	          urlParams.append('tenant', tracingService.tempoConfig?.tenant);
102	        }
103	        return `${baseUrl}?${urlParams.toString()}`;
104	      }
105	
106	      return baseUrl;
107	    };
108	
109	    return allNavMenuItems
110	      .filter(item => {
111	        if (item.id === 'mesh') {
112	          return isControlPlaneAccessible();
113	        }
114	
115	        return true;
116	      })
117	      .map(item => {
118	        let title = item.title;
119	
120	        if (item.id === 'tracing') {
121	          if (baseTracingUrl) {
122	            const tracingUrlWithParams = buildTracingUrlWithParams(baseTracingUrl);
123	            return <ExternalLink key={item.to} href={tracingUrlWithParams} name={t(title)} />;
124	          }
125	          return null;
126	        }
127	
128	        return (
129	          <NavItem isActive={activeMenuItem === item} key={item.to}>
130	            <Link id={item.id} to={item.to} onClick={() => navigate(item.to)}>
131	              {t(title)}
132	            </Link>
133	          </NavItem>
134	        );
135	      });
136	  };
137	
138	  return (
139	    <Nav aria-label="Nav">
140	      <NavList className={navListStyle}>{renderMenuItems()}</NavList>
141	    </Nav>
142	  );
143	};

